"use strict";(globalThis.webpackChunkwebsite=globalThis.webpackChunkwebsite||[]).push([[989],{5282:(e,n,t)=>{t.r(n),t.d(n,{assets:()=>c,contentTitle:()=>r,default:()=>l,frontMatter:()=>a,metadata:()=>i,toc:()=>d});const i=JSON.parse('{"id":"training/part1-foundations/auth-clustering-and-session-token-architecture","title":"8. Auth Clustering and Session Token Architecture","description":"8.1 The Problem: In-Memory, Node-Specific Session Tokens","source":"@site/docs/training/part1-foundations/8-auth-clustering-and-session-token-architecture.md","sourceDirName":"training/part1-foundations","slug":"/training/part1-foundations/auth-clustering-and-session-token-architecture","permalink":"/rsapsdocumentation/docs/training/part1-foundations/auth-clustering-and-session-token-architecture","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":8,"frontMatter":{"title":"8. Auth Clustering and Session Token Architecture","sidebar_position":8},"sidebar":"docsSidebar","previous":{"title":"7. Service Startup, Ports, and API Validation","permalink":"/rsapsdocumentation/docs/training/part1-foundations/service-startup-ports-and-api-validation"},"next":{"title":"9. Reference Production Architecture and Sizing","permalink":"/rsapsdocumentation/docs/training/part1-foundations/reference-production-architecture-and-sizing"}}');var s=t(4848),o=t(8453);const a={title:"8. Auth Clustering and Session Token Architecture",sidebar_position:8},r="8. Auth Clustering and Session Token Architecture",c={},d=[{value:"8.1 The Problem: In-Memory, Node-Specific Session Tokens",id:"81-the-problem-in-memory-node-specific-session-tokens",level:2},{value:"8.2 The Solution: Machine IDs and Mod-20 Encoding",id:"82-the-solution-machine-ids-and-mod-20-encoding",level:2},{value:"8.3 Configuration",id:"83-configuration",level:2},{value:"8.4 When Clustering Is Unnecessary \u2014 and the Redis Future",id:"84-when-clustering-is-unnecessary--and-the-redis-future",level:2},{value:"8.5 Session Timeouts and the Load Balancer Interaction",id:"85-session-timeouts-and-the-load-balancer-interaction",level:2}];function u(e){const n={h1:"h1",h2:"h2",header:"header",p:"p",...(0,o.R)(),...e.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsx)(n.header,{children:(0,s.jsx)(n.h1,{id:"8-auth-clustering-and-session-token-architecture",children:"8. Auth Clustering and Session Token Architecture"})}),"\n",(0,s.jsx)(n.h2,{id:"81-the-problem-in-memory-node-specific-session-tokens",children:"8.1 The Problem: In-Memory, Node-Specific Session Tokens"}),"\n",(0,s.jsx)(n.p,{children:"The two-step API pattern (authenticate \u2192 session token \u2192 admin call) creates a distributed-systems problem in production. Session tokens are in-memory, application-specific artifacts stored only on the node that issued them. With four MS nodes behind a load balancer, a client may authenticate against node 1 (receiving node 1's session token) and then have its admin call routed to node 2 \u2014 which has no knowledge of that token and cannot validate it."}),"\n",(0,s.jsx)(n.h2,{id:"82-the-solution-machine-ids-and-mod-20-encoding",children:"8.2 The Solution: Machine IDs and Mod-20 Encoding"}),"\n",(0,s.jsx)(n.p,{children:"Prime's auth clustering assigns each participating node a machine ID from 1 to 20 (20 is a practical ceiling; the largest real deployment observed is 18 nodes). When a node generates a session token, the machine ID is embedded into the token via a mod-20 operation \u2014 meaning any node can determine, just by inspecting the 8-digit token, which node issued it. When an admin call lands on a different node, MS internally forwards the token to the issuing node for validation; if the issuer confirms validity, the receiving node performs the requested activity. Only the issuing node can validate its own tokens, because the token state lives solely in that node's memory."}),"\n",(0,s.jsx)(n.h2,{id:"83-configuration",children:"8.3 Configuration"}),"\n",(0,s.jsx)(n.p,{children:"Auth clustering is configured in authclusterconfig and is disabled out of the box (single localhost entry). Enabling it means uncommenting the machine entries (M01, M02, \u2026), assigning each node's FQDN a unique machine ID, and \u2014 critically \u2014 keeping the configuration identical across every node (if a server is machine 1 in one file, it is machine 1 in all of them). Restart the services and the nodes become cluster-aware."}),"\n",(0,s.jsx)(n.h2,{id:"84-when-clustering-is-unnecessary--and-the-redis-future",children:"8.4 When Clustering Is Unnecessary \u2014 and the Redis Future"}),"\n",(0,s.jsx)(n.p,{children:"If the customer's load balancer supports sticky sessions (e.g., source-IP persistence), requests within a session always reach the issuing node and auth clustering is unneeded. Clustering exists for customers with no load balancer or without persistence capability. Separately, Prime now supports containerized (Docker) deployment, and for that model the team supports Redis-backed session clustering: session tokens are written to a Redis cache rather than node memory, and validation reads from Redis \u2014 removing the node-affinity problem entirely. Redis configuration details were declared out of scope for Day 1."}),"\n",(0,s.jsx)(n.h2,{id:"85-session-timeouts-and-the-load-balancer-interaction",children:"8.5 Session Timeouts and the Load Balancer Interaction"}),"\n",(0,s.jsx)(n.p,{children:"Token lifetimes are configured near the end of authconfig.xml via two values: an idle timeout (expiry when unused) and a lifetime timeout (absolute maximum \u2014 e.g., 8 hours regardless of activity). Common customer configurations include 15/30 and 15/60 minutes. A subtle field gotcha received emphasis: the load balancer's own persistence timeout must be greater than or equal to the authconfig timeouts. If the LB persistence window (say, 15 minutes) is shorter than the token lifetime, the LB forgets which node owns the session and effectively overrides Prime's configuration. The load balancer is customer-owned infrastructure outside Prime's control \u2014 and, as attendees noted from field experience, coordinating changes with customer network teams is frequently the largest source of onsite delay."})]})}function l(e={}){const{wrapper:n}={...(0,o.R)(),...e.components};return n?(0,s.jsx)(n,{...e,children:(0,s.jsx)(u,{...e})}):u(e)}},8453:(e,n,t)=>{t.d(n,{R:()=>a,x:()=>r});var i=t(6540);const s={},o=i.createContext(s);function a(e){const n=i.useContext(o);return i.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function r(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(s):e.components||s:a(e.components),i.createElement(o.Provider,{value:n},e.children)}}}]);